// MQTT adapter validation — guard against malformed envelopes.
const p = msg.payload;
const required = ['type', 'schema_version', 'timestamp', 'site_id', 'smart_energy', 'smart_city'];
const missing = required.filter(f => p[f] === undefined);
if (missing.length > 0) {
    node.error('mqtt-adapter: invalid envelope, missing fields: ' + missing.join(', '), msg);
    return null;
}
if (p.type !== 'sim.tick') {
    node.error('mqtt-adapter: invalid envelope.type ' + p.type, msg);
    return null;
}
flow.set('last_mqtt_tick', p.timestamp);
flow.set('mqtt_tick_count', (flow.get('mqtt_tick_count') || 0) + 1);
return msg;

// Split unified envelope into per-feed MQTT messages.
const envelope = msg.payload;
const ts = envelope.timestamp;
const siteId = envelope.site_id;
const cityId = envelope.smart_city.city_id || 'city';
const msgs = [];

function emit(topic, key, payload, qos, retain) {
    msgs.push({
        topic: topic,
        payload: JSON.stringify(payload),
        qos: qos,
        retain: retain,
        _entityKey: key
    });
}

for (const m of (envelope.smart_energy.meters || [])) {
    emit('facis/' + siteId + '/meter/' + (m.meter_id || 'unknown'), m.meter_id, m, 1, false);
}
for (const p of (envelope.smart_energy.pv || [])) {
    const id = p.system_id || p.pv_system_id || 'unknown';
    emit('facis/' + siteId + '/pv/' + id, id, p, 1, false);
}
if (envelope.smart_energy.weather) {
    emit('facis/' + siteId + '/weather/current', 'weather', envelope.smart_energy.weather, 0, true);
}
if (envelope.smart_energy.price) {
    emit('facis/' + siteId + '/prices/spot', 'price', envelope.smart_energy.price, 1, true);
}
for (const c of (envelope.smart_energy.consumers || [])) {
    emit('facis/' + siteId + '/loads/' + (c.device_type || 'device'), c.device_id, c, 0, false);
}
for (const l of (envelope.smart_city.streetlights || [])) {
    emit('facis/' + cityId + '/light/' + (l.zone_id || 'zone') + '/' + (l.light_id || 'light'), l.light_id, l, 0, false);
}
for (const t of (envelope.smart_city.traffic || [])) {
    emit('facis/' + cityId + '/traffic/' + (t.zone_id || 'zone'), t.zone_id, t, 0, false);
}
for (const e of (envelope.smart_city.events || [])) {
    emit('facis/' + cityId + '/event/' + (e.zone_id || 'zone'), e.zone_id, e, 1, false);
}
if (envelope.smart_city.visibility) {
    emit('facis/' + cityId + '/weather', cityId, envelope.smart_city.visibility, 0, true);
}

// Status retained topic
msgs.push({
    topic: 'facis/' + siteId + '/simulation/status',
    payload: JSON.stringify({
        timestamp: ts,
        last_seed: envelope.seed,
        mode: envelope.mode
    }),
    qos: 1,
    retain: true
});

node.send([msgs]);
return null;

